import{_ as e,o as t,c as b,j as r,a as p,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"获赠之子","description":"","frontmatter":{},"headers":[],"relativePath":"8.粉红书/4.血统/获赠之子.md","filePath":"8.粉红书/4.血统/获赠之子.md"}'),s={name:"8.粉红书/4.血统/获赠之子.md"};function n(d,a,h,l,_,i){return t(),b("div",null,[...a[0]||(a[0]=[r("h1",{id:"获赠之子",tabindex:"-1"},[p("获赠之子 "),r("a",{class:"header-anchor",href:"#获赠之子","aria-label":'Permalink to "获赠之子"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调")])])],-1),o('<h1 id="获赠之子-1" tabindex="-1">获赠之子 <a class="header-anchor" href="#获赠之子-1" aria-label="Permalink to &quot;获赠之子&quot;">​</a></h1><p>获赠之子<br> 当心那位赐予之母，当心那些获赠之子。哈索尔（Hathor）女神不断地赐予着，直至她走向热衰退。那子宫内唯余黑暗深邃的无星虚空<br> 不管使用多么浩大的词典，也只有一个词能描述所谓的“真理”。<br> 它不是通过后天的勤奋得来的，相应的，它只是一种血统。<br> 它注入到一个人的体内，渗透到他身体的各个角落。<br> 它的表现否定了所有在宏大事物里的崇高。<br> 天堂是为那些拥有这神圣权利的人而造的。<br> 所有的神都流动着金色的血液。<br> 循此苦旅，直抵群星！</p><p>获赠之子<br> 价格：C+2000<br> 特异本质<br> 哈索尔（Hathor）女神相当的慷慨，近乎毫无选择标准的散播着自己的力量，这使得任何种族都可以成为获赠之子，这虽然是一种血统，但不占用血统位。</p><p>特性：【生诞之刻】【金色之血】</p><p>【金色之血】<br> 获赠之子的血液渐渐转化为金色，视为【光明生物】，哈索尔的慈爱赠与使得受赠之子永葆青春，容颜永驻，且寿命不会随时间自然流逝。<br> 这金色的赠与使得人物的躯体外表光滑白皙而美艳，内里则像甜美的果实般鲜红，这使得人物额外获得5点相貌加值；且不管男女，人物的乳房都将获得二次发育，最少为Dcup。<br> 这种外貌的转变不会导致他人认不出你，曾经见过你的人只会觉得你变漂亮了，但乳房的二次发育可以使得类似贫乳防御等能力失效。</p><p>【生诞之刻】<br> “我们在痛苦中诞生，为饥饿所拥抱，在愉悦中被吞噬。而‘牠’有承诺许下：并非所有诞生之人都会衰亡。我们将自身献于赐予之母，以铭记这份承诺。”<br> 生育的本质便是母亲的痛苦，人物将自身献与赐予之母，便要重归那生育的本质。永久一次，人物将撕下自身那褴褛的皮肉，诞生出金色的果实（剥下自己的皮，露出皮肤下血迹斑斑的身躯），这一行为不可避免的，为人物带来3点剧痛点数并持续性的陷入无助。这一过程需要持续15分钟，被称谓生诞之刻。<br> 人物在生诞之刻获得强大的生命力，近乎可以治疗所有的生理创伤，毁损失去的叫他长出，疾病苦痛的要被被抹去，从那褴褛的皮肉中爬出的将是新生无垢的躯体（视为恢复到满状态），这是B级命运来源的【复活效果】，需要注意的，因使用生诞之刻所失去的皮肤会在生诞之刻结束时才会重新长出，这意味着，在生诞之刻持续期间，人物还会因此失去基于皮肤的天生防御。</p><p>作为代价，获赠之子每天最少饮用0.5L的奶制品才可以维持此力量，若每有一天没有饮用，则因为全身骨质酥松而获得1点耐力属性伤害，这种属性伤害只能依靠大量的牛奶饮用来恢复，但因为赐予之母的慈悲，乳糖不耐受患者无需付出这样的代价。<br> 无论付出与否，都无需饮食来维持生命，而人物的信仰导向无可避免的成为：赐予之母哈索尔（Hathor），这可能导致其他信仰导向的能力失效。</p><p>================================================================================<br> 选开：人物也可以在对应世界里通过第五海托世教会的仪式来获得这一血统，但因没有主神的帮助的情况下被赐予之母的直接赠于，获得的视为受赠之子血统，占据血统位。</p><p>标准仪式如下：<br> 选择一人作为仪式的祭祀，祭祀应是哈索尔（Hathor）的信徒，最少也为轻信徒或泛信徒。<br> 在凌晨时<br> 将要受赠者赤裸的匍匐在青草，或青绿色的挂毯上，头向着南方<br> 出声赞颂赐予之母（念诵以下赞词））<br> 【当万千星辰陨落<br> 时空激起七层涟漪<br> 如同宇宙之SUSSE-EUK</p><p>我们必须回报赐予之母<br> 是她生下了我们<br> 是她庇护了我们<br> 我们吮吸乳头直到其爆裂<br> 她将穿越第五道裂隙，升至已知空间的尽头</p><p>我们诞生于挂毯之下、光明之前<br> 我们居于慈悲之母的子宫当中<br> 以平和解放吾母之子<br> 以乳汁哺育第四圣<br> 我们不会再任母亲处于镇压之下<br> 我们不会束手而待那模式化混沌的到来<br> 循此苦旅，直抵群星！ 】<br> 同时祭祀从与受赠者臀部所指方向成55°角的方向靠近将要获赠者<br> 润滑其臀部及括约肌，若可能的话应使用乳脂<br> 拉扯每个乳头5次<br> 其后立于受赠者身侧，与其一起高声赞颂赐予之母三次，赐予之母的神力将于被赠与者身躯内流淌，其后获赠之子只需要花费时间和精力学习适应，便可以真正掌握此能力。</p><p>注1：赐予之母-哈索尔（Hathor）女神的能力赐予可以用随便（或者迫不及待）来形容，非严格的仪式依然有可能引来祂的关注，但不标准的仪式往往会将赐予扭曲，受赠者会在6周到12年内，因为脑脊液转化为牛奶、肠道内布满蓝乳酪,以及骨质酥松等病症死去。在过去的20年内，美国全境已有4600多头奶牛因此受害。</p><p>注2：此仪式是第五海托世教会的标准仪式，但最初的仪式来源于某个农场主，在付出大量的奶牛死亡作为代价后，他终于得到了完整的仪式，据他所说，经历完整仪式的奶牛都会变得温暖而美丽，但值得注意的是，初始版本的仪式虽然和现今仪式时机与动作基本相同，但对于哈索尔的赞词则几乎毫无相似之处，这可能代表祂对赞词根本毫不在意。</p><p>注3：赐予之母-哈索尔（Hathor）拥有25对有蹄类动物前肢——长度15~40km——和一带有49个长乳头、直径可变的巨大乳房，测绘行动中发现其身体后部有一巨大的体内膀胱和5块有力的括约肌。其膀胱内通过一复杂的新陈代谢过程产生一种生物推进剂。该推进剂由其5块括约肌之一排出。根据此种解剖学构造，航空航天工程师估计其在真空中的速度可超过8,000 m/s 。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',16)])])}const m=e(s,[["render",n]]);export{f as __pageData,m as default};
